package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	rsaKeySize         = 2048
	jwtExpiration      = 5 * time.Minute
	IdentitySecretName = "picod-router-identity"
	PrivateKeyDataKey  = "private.pem"
	PublicKeyDataKey   = "public.pem"
)

var IdentityNamespace = "default"

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func init() {
	if ns := os.Getenv("AGENTCUBE_NAMESPACE"); ns != "" {
		IdentityNamespace = ns
	}
}

func NewJWTManager() (*JWTManager, error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key: %w", err)
	}

	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
		clientset:  nil,
	}, nil
}

func (j *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now().Unix()
	tokenClaims := jwt.MapClaims{
		"exp": now + int64(jwtExpiration.Seconds()),
		"iat": now,
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		tokenClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKey() *rsa.PublicKey {
	return j.publicKey
}

func (j *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	var clientset kubernetes.Interface
	var err error

	if j.clientset != nil {
		clientset = j.clientset
	} else {
		restConfig, err := rest.InClusterConfig()
		if err != nil {
			klog.Info("Not in cluster, using ephemeral JWT keys")
			return nil
		}
		clientset, err = kubernetes.NewForConfig(restConfig)
		if err != nil {
			klog.Info("Failed to create in-cluster clientset, using ephemeral JWT keys")
			return nil
		}
	}

	secret, err := clientset.CoreV1().Secrets(IdentityNamespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		if k8serrors.IsNotFound(err) {
			return j.createSecret(ctx, clientset)
		}
		return fmt.Errorf("failed to get identity secret: %w", err)
	}

	return j.loadSecret(secret)
}

func (j *JWTManager) createSecret(ctx context.Context, clientset kubernetes.Interface) error {
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(j.privateKey),
	})

	pubBytes, _ := x509.MarshalPKIXPublicKey(j.publicKey)
	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubBytes,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
			Labels: map[string]string{
				"app":       "agentcube",
				"component": "router",
			},
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
	}

	_, err := clientset.CoreV1().Secrets(IdentityNamespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create identity secret: %w", err)
	}

	klog.Info("Created identity secret for JWT signing")
	return nil
}

func (j *JWTManager) loadSecret(secret *corev1.Secret) error {
	privateKeyData, ok := secret.Data[PrivateKeyDataKey]
	if !ok {
		return errors.New("private key not found in secret")
	}

	block, _ := pem.Decode(privateKeyData)
	if block == nil {
		return errors.New("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	j.privateKey = privateKey
	j.publicKey = &privateKey.PublicKey

	return nil
}

