package router

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"strings"
	"time"

	apierrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	AgentRuntimeKind    = "AgentRuntime"
	CodeInterpreterKind = "CodeInterpreter"
	SessionIDHeader     = "x-agentcube-session-id"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
	authToken       string
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	authToken := loadWorkloadManagerAuthToken()

	httpClient := &http.Client{
		Timeout: 2 * time.Minute,
		Transport: &http.Transport{
			MaxIdleConnsPerHost: 100,
		},
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      httpClient,
		authToken:       authToken,
	}, nil
}

func loadWorkloadManagerAuthToken() string {
	tokenData, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		if !os.IsNotExist(err) {
			klog.Warningf("Failed to read service account token: %v", err)
		}
		return ""
	}
	return strings.TrimSpace(string(tokenData))
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return m.createSession(ctx, namespace, name, kind)
	}

	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, NewSessionNotFoundError(sessionID)
		}
		return nil, fmt.Errorf("failed to get sandbox: %w", err)
	}

	return sandbox, nil
}

func (m *manager) createSession(ctx context.Context, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	endpoint := m.workloadMgrAddr
	if kind == AgentRuntimeKind {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	} else if kind == CodeInterpreterKind {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	}

	reqBody := map[string]interface{}{
		"kind":      kind,
		"name":      name,
		"namespace": namespace,
	}

	bodyBytes, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, "POST", endpoint, bytes.NewReader(bodyBytes))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if m.authToken != "" {
		req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", m.authToken))
	}

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to create session: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		if resp.StatusCode == http.StatusNotFound {
			return nil, NewSandboxTemplateNotFoundError(namespace, name, kind)
		}
		return nil, fmt.Errorf("workload manager returned status %d: %s", resp.StatusCode, string(respBody))
	}

	var createResp types.CreateSandboxResponse
	if err := json.Unmarshal(respBody, &createResp); err != nil {
		return nil, fmt.Errorf("failed to unmarshal response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("session ID is empty in response")
	}

	sandbox := &types.SandboxInfo{
		ID:        createResp.Sandbox.ID,
		Name:      createResp.Sandbox.Name,
		Namespace: namespace,
		Status:    createResp.Sandbox.Status,
		EntryPoint: types.SandboxEntryPoint{
			URL:      createResp.Sandbox.EntryPoint.URL,
			Protocol: createResp.Sandbox.EntryPoint.Protocol,
			Port:     createResp.Sandbox.EntryPoint.Port,
		},
	}

	return sandbox, nil
}

type SessionError struct {
	SessionID string
	Message   string
	Code      int
}

func (e *SessionError) Error() string {
	return e.Message
}

func NewSessionNotFoundError(sessionID string) *SessionError {
	return &SessionError{
		SessionID: sessionID,
		Message:   fmt.Sprintf("session %s not found", sessionID),
		Code:      http.StatusNotFound,
	}
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) *SessionError {
	return &SessionError{
		Message: fmt.Sprintf("sandbox template not found: namespace=%s, name=%s, kind=%s", namespace, name, kind),
		Code:    http.StatusNotFound,
	}
}

func handleGetSandboxError(c *gin.Context, err error) {
	if apiStatus, ok := err.(apierrors.APIStatus); ok {
		code := apiStatus.Status().Code
		if code == 0 {
			code = http.StatusInternalServerError
		}
		message := apiStatus.Status().Message
		if message == "" {
			message = err.Error()
		}
		if code == http.StatusInternalServerError {
			message = "internal server error"
		}
		c.JSON(code, gin.H{"error": message})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

