func (s *Server) buildReverseProxy(sandbox *types.SandboxInfo, path string) *httputil.ReverseProxy {
	targetURL := s.determineUpstreamURL(sandbox, path)
	if targetURL == nil {
		return nil
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host

		normalizedPath := req.URL.Path
		if !strings.HasPrefix(normalizedPath, "/") {
			normalizedPath = "/" + normalizedPath
		}
		req.URL.Path = normalizedPath
		req.RawURL = ""

		req.Host = targetURL.Host

		originalForwardedFor := req.Header.Get("X-Forwarded-For")
		clientIP := getClientIP(req)
		if originalForwardedFor != "" {
			req.Header.Set("X-Forwarded-For", fmt.Sprintf("%s, %s", originalForwardedFor, clientIP))
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		req.Header.Set("X-Forwarded-Host", req.Host)
		if req.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		if s.jwtManager != nil && needsJWT(sandbox) {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandbox.ID,
			})
			if err != nil {
				klog.Errorf("Failed to generate JWT: %v", err)
			} else {
				req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
			}
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandbox.ID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, req *http.Request, err error) {
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		} else if strings.Contains(errMsg, "timeout") {
			w.WriteHeader(http.StatusGatewayTimeout)
			w.Write([]byte(`{"error":"sandbox timeout"}`))
		} else {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		}
	}

	return proxy
}

func (s *Server) determineUpstreamURL(sandbox *types.SandboxInfo, path string) *url.URL {
	if sandbox.EntryPoint.URL == "" {
		return nil
	}

	ep := sandbox.EntryPoint
	scheme := strings.ToLower(ep.Protocol)
	if !strings.Contains(scheme, "://") {
		scheme = scheme + "://"
	}

	endpoint := ep.URL
	if !strings.Contains(endpoint, "://") {
		endpoint = scheme + endpoint
	}

	targetURL, err := url.Parse(endpoint)
	if err != nil {
		klog.Errorf("Failed to parse endpoint URL: %v", err)
		return nil
	}

	return targetURL
}

func needsJWT(sandbox *types.SandboxInfo) bool {
	return sandbox.Status == "Sandbox" || sandbox.Status == "SandboxClaim"
}

func getClientIP(req *http.Request) string {
	forwarded := req.Header.Get("X-Forwarded-For")
	if forwarded != "" {
		parts := strings.Split(forwarded, ",")
		return strings.TrimSpace(parts[0])
	}

	remoteAddr := req.RemoteAddr
	if ip, _, err := net.SplitHostPort(remoteAddr); err == nil {
		return ip
	}
	return remoteAddr
}

func normalizePath(path string) string {
	if !strings.HasPrefix(path, "/") {
		return "/" + path
	}
	return path
}

