	engine.GET("/health/live", handleHealthLiveWithServer)
	engine.GET("/health/ready", handleHealthReadyWithServer)

	httpTransport := &http.Transport{
		IdleConnTimeout: 0,
	}

	httpServer := &http.Server{
		Addr:         cfg.Port,
		Handler:      engine,
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
		TLSConfig:    &tls.Config{},
		ReadHeaderTimeout: 10 * time.Second,
	}

	s := &Server{
		config:         cfg,
