func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	s.handleInvoke(c, namespace, name, path, AgentRuntimeKind)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	s.handleInvoke(c, namespace, name, path, CodeInterpreterKind)
}

func (s *Server) handleInvoke(c *gin.Context, namespace, name, path, kind string) {
	sessionID := c.GetHeader(SessionIDHeader)

	ctx := c.Request.Context()

	sandbox, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, kind)
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	if sandbox == nil || sandbox.EntryPoint.URL == "" {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	err = s.storeClient.UpdateSessionLastActivity(ctx, sandbox.ID, time.Now())
	if err != nil {
		klog.Warningf("Failed to update last activity: %v", err)
	}

	targetURL := determineUpstreamURL(sandbox, path)
	if targetURL == nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	proxy := buildReverseProxy(targetURL, sandbox, s.jwtManager)
	proxy.ServeHTTP(c.Writer, c.Request)

	err = s.storeClient.UpdateSessionLastActivity(ctx, sandbox.ID, time.Now())
	if err != nil {
		klog.Warningf("Failed to update last activity after proxy: %v", err)
	}
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	klog.Errorf("Error getting sandbox: %v", err)
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (s *Server) Start() error {
