package workload

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type CreateSessionRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

type CreateSessionResponse struct {
	SessionID   string                 `json:"sessionId"`
	SandboxID   string                 `json:"sandboxId"`
	SandboxName string                 `json:"sandboxName"`
	EntryPoints []types.SandboxEntryPoint `json:"entryPoints"`
}

type Server struct {
	config            *Config
	router            *gin.Engine
	httpServer        *http.Server
	storeClient       store.Store
}

type Config struct {
	Port             string
	EnableAuth       bool
}

func NewServer(cfg *Config) (*Server, error) {
	storeClient, err := store.Storage()
	if err != nil {
		return nil, fmt.Errorf("failed to initialize store: %w", err)
	}

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger())
	router.Use(gin.Recovery())

	server := &Server{
		config:      cfg,
		router:      router,
		storeClient: storeClient,
	}

	server.setupRoutes()

	httpServer := &http.Server{
		Addr:         ":" + cfg.Port,
		Handler:      router,
		ReadTimeout:  30 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	server.httpServer = httpServer

	return server, nil
}

func (s *Server) setupRoutes() {
	s.router.GET("/health", s.handleHealth)

	v1 := s.router.Group("/v1")
	if s.config.EnableAuth {
		v1.Use(authMiddleware())
	}

	v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSession)
	v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSession)
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req CreateSessionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.Kind == "" {
		req.Kind = "AgentRuntime"
	}

	sandbox := &types.SandboxInfo{
		ID:        generateSessionID(),
		Name:      req.Name,
		Namespace: req.Namespace,
		Status:    "creating",
		EntryPoint: types.SandboxEntryPoint{
			URL:      fmt.Sprintf("http://%s.default.svc.cluster.local:8080", req.Name),
			Protocol: "http",
			Port:     8080,
		},
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(8 * time.Hour),
		LastActivityTime: time.Now().Unix(),
	}

	err := s.storeClient.StoreSandbox(c.Request.Context(), sandbox)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to store sandbox: %v", err)})
		return
	}

	resp := CreateSessionResponse{
		SessionID:   sandbox.ID,
		SandboxID:   sandbox.ID,
		SandboxName: sandbox.Name,
		EntryPoints: []types.SandboxEntryPoint{sandbox.EntryPoint},
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req CreateSessionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.Kind == "" {
		req.Kind = "CodeInterpreter"
	}

	sandbox := &types.SandboxInfo{
		ID:        generateSessionID(),
		Name:      req.Name,
		Namespace: req.Namespace,
		Status:    "creating",
		EntryPoint: types.SandboxEntryPoint{
			URL:      fmt.Sprintf("http://%s.default.svc.cluster.local:8080", req.Name),
			Protocol: "http",
			Port:     8080,
		},
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(8 * time.Hour),
		LastActivityTime: time.Now().Unix(),
	}

	err := s.storeClient.StoreSandbox(c.Request.Context(), sandbox)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to store sandbox: %v", err)})
		return
	}

	resp := CreateSessionResponse{
		SessionID:   sandbox.ID,
		SandboxID:   sandbox.ID,
		SandboxName: sandbox.Name,
		EntryPoints: []types.SandboxEntryPoint{sandbox.EntryPoint},
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleDeleteSession(c *gin.Context) {
	sessionID := c.Param("sessionId")

	err := s.storeClient.DeleteSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusOK, gin.H{"deleted": true})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to delete session: %v", err)})
		return
	}

	c.JSON(http.StatusOK, gin.H{"deleted": true})
}

func (s *Server) Start() error {
	klog.Infof("Starting workload manager on port %s", s.config.Port)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop(ctx context.Context) error {
	return s.httpServer.Shutdown(ctx)
}

func generateSessionID() string {
	return fmt.Sprintf("session-%d", time.Now().UnixNano())
}

func authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "authorization header required"})
			c.Abort()
			return
		}
		c.Next()
	}
}

