func main() {
	port := flag.String("port", "8080", "Port to listen on")
	enableAuth := flag.Bool("enable-auth", false, "Enable authentication")

	klog.InitFlags(flag.Parse())
	flag.Set("v", "2")

	cfg := &workload.Config{
		Port:       *port,
		EnableAuth: *enableAuth,
	}

	server, err := workload.NewServer(cfg)
	if err != nil {
