func (s *Server) handleFileUpload(c *gin.Context) {
	contentType := c.Request.Header.Get("Content-Type")
	var fileData []byte
	var filename string
	var mode os.FileMode = 0644

	if len(contentType) > 0 && contentType != "application/json" {
		file, header, err := c.Request.FormFile("file")
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "file is required"})
			return
		}
		defer file.Close()

		fileData, err = io.ReadAll(file)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read file"})
			return
		}
		filename = header.Filename
	} else {
		var req struct {
			Path    string `json:"path"`
			Content string `json:"content"`
			Mode    string `json:"mode"`
		}
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}
		filename = req.Path
		if req.Content != "" {
			fileData, err = base64.StdEncoding.DecodeString(req.Content)
			if err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": "invalid base64 content"})
				return
			}
		}
		if req.Mode != "" {
			var err error
			mode, err = parseMode(req.Mode)
			if err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": "invalid mode"})
				return
			}
		}
	}

	path := filepath.Join(s.config.Workspace, filename)
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create directory"})
		return
	}

	if err := os.WriteFile(path, fileData, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to write file"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"path": filename})
}

func (s *Server) handleFileList(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required"})
		return
	}

	fullPath := filepath.Join(s.config.Workspace, path)
	entries, err := os.ReadDir(fullPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read directory"})
		return
	}

	var files []FileInfo
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileInfo{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime().Unix(),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, gin.H{"files": files})
}

func (s *Server) handleFileDownload(c *gin.Context) {
	path := c.Param("path")
	fullPath := filepath.Join(s.config.Workspace, path)

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filepath.Base(path)))
	c.File(fullPath)
}

