"""Code Interpreter Client."""

import os
from typing import Optional, Dict, Any, List
import requests
from urllib.parse import urljoin

from agentcube.exceptions import SessionError, DataPlaneError, CommandExecutionError


class CodeInterpreterClient:
    """Client for Code Interpreter sessions."""

    def __init__(
        self,
        name: str,
        namespace: str = "default",
        ttl: Optional[int] = None,
        workload_manager_url: Optional[str] = None,
        router_url: Optional[str] = None,
        auth_token: Optional[str] = None,
        session_id: Optional[str] = None,
    ):
        self.name = name
        self.namespace = namespace
        self.ttl = ttl
        self.workload_manager_url = workload_manager_url or os.environ.get("WORKLOAD_MANAGER_URL")
        self.router_url = router_url or os.environ.get("ROUTER_URL")
        self.auth_token = auth_token or os.environ.get("AUTH_TOKEN")
        self.session_id = session_id

        if not self.router_url:
            raise ValueError("router_url is required")

        self._control_plane = None
        self._data_plane = None
        self._session_created = False

    def __enter__(self):
        self.create_session()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stop()

    def create_session(self):
        """Create a new code interpreter session."""
        if not self.workload_manager_url:
            raise ValueError("workload_manager_url is required")

        url = f"{self.workload_manager_url}/v1/code-interpreter"
        payload = {
            "name": self.name,
            "namespace": self.namespace,
        }
        if self.ttl:
            payload["ttl"] = self.ttl

        headers = {}
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        response = requests.post(url, json=payload, headers=headers, timeout=120)
        if response.status_code != 200:
            raise SessionError(f"Failed to create session: {response.text}")

        data = response.json()
        self.session_id = data.get("sessionId")
        if not self.session_id:
            raise SessionError("Session ID not returned")

        self._session_created = True
        self._data_plane = f"{self.router_url}/v1/namespaces/{self.namespace}/code-interpreters/{self.name}/invocations/"

    def execute_command(self, command: List[str], timeout: Optional[int] = None) -> Dict[str, Any]:
        """Execute a command in the sandbox."""
        if not self._data_plane:
            raise DataPlaneError("Data plane not initialized")

        payload = {
            "command": command,
        }
        if timeout:
            payload["timeout"] = f"{timeout}s"

        headers = {
            "Content-Type": "application/json",
            "x-agentcube-session-id": self.session_id,
        }
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        read_timeout = (timeout or 60) + 2.0
        response = requests.post(
            f"{self._data_plane}api/execute",
            json=payload,
            headers=headers,
            timeout=(5.0, read_timeout),
        )

        if response.status_code != 200:
            raise CommandExecutionError(f"Command failed: {response.text}")

        result = response.json()
        if result.get("exit_code", 0) != 0:
            raise CommandExecutionError(
                result.get("stderr", "Command failed"),
                exit_code=result.get("exit_code"),
                stderr=result.get("stderr"),
                command=" ".join(command),
            )

        return result

    def run_code(self, code: str, language: str = "python") -> Dict[str, Any]:
        """Run code in the sandbox."""
        return self.execute_command([language, "-c", code])

    def write_file(self, path: str, content: str):
        """Write a file to the sandbox."""
        if not self._data_plane:
            raise DataPlaneError("Data plane not initialized")

        import base64
        payload = {
            "path": path,
            "content": base64.b64encode(content.encode()).decode(),
        }

        headers = {
            "Content-Type": "application/json",
            "x-agentcube-session-id": self.session_id,
        }
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        response = requests.post(
            f"{self._data_plane}api/files",
            json=payload,
            headers=headers,
            timeout=30,
        )

        if response.status_code != 200:
            raise DataPlaneError(f"Failed to write file: {response.text}")

    def upload_file(self, path: str, file_data: bytes):
        """Upload a file to the sandbox."""
        if not self._data_plane:
            raise DataPlaneError("Data plane not initialized")

        files = {"file": (path, file_data)}
        data = {"path": path}

        headers = {"x-agentcube-session-id": self.session_id}
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        response = requests.post(
            f"{self._data_plane}api/files",
            files=files,
            data=data,
            headers=headers,
            timeout=30,
        )

        if response.status_code != 200:
            raise DataPlaneError(f"Failed to upload file: {response.text}")

    def download_file(self, path: str) -> bytes:
        """Download a file from the sandbox."""
        if not self._data_plane:
            raise DataPlaneError("Data plane not initialized")

        headers = {"x-agentcube-session-id": self.session_id}
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        response = requests.get(
            f"{self._data_plane}files/{path}",
            headers=headers,
            timeout=30,
        )

        if response.status_code != 200:
            raise DataPlaneError(f"Failed to download file: {response.text}")

        return response.content

    def list_files(self, path: str = ".") -> List[Dict[str, Any]]:
        """List files in the sandbox."""
        if not self._data_plane:
            raise DataPlaneError("Data plane not initialized")

        headers = {"x-agentcube-session-id": self.session_id}
        if self.auth_token:
            headers["Authorization"] = f"Bearer {self.auth_token}"

        response = requests.get(
            f"{self._data_plane}api/files",
            params={"path": path},
            headers=headers,
            timeout=30,
        )

        if response.status_code != 200:
            raise DataPlaneError(f"Failed to list files: {response.text}")

        return response.json().get("files", [])

    def stop(self):
        """Stop and cleanup the session."""
        if self._session_created and self.session_id and self.workload_manager_url:
            try:
                url = f"{self.workload_manager_url}/v1/code-interpreter/sessions/{self.session_id}"
                headers = {}
                if self.auth_token:
                    headers["Authorization"] = f"Bearer {self.auth_token}"
                requests.delete(url, headers=headers, timeout=10)
            except Exception:
                pass

        self._session_created = False
        self._data_plane = None

"""Agent Runtime Client."""

import os
from typing import Optional, Dict, Any
import requests

from agentcube.exceptions import SessionError


class AgentRuntimeClient:
    """Client for Agent Runtime sessions."""

    def __init__(
        self,
        agent_name: str,
        namespace: str = "default",
        router_url: Optional[str] = None,
        session_id: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: int = 5,
    ):
        self.agent_name = agent_name
        self.namespace = namespace
        self.router_url = router_url or os.environ.get("ROUTER_URL")
        self.session_id = session_id
        self.timeout = timeout
        self.connect_timeout = connect_timeout

        if not self.router_url:
            raise ValueError("router_url is required")

        self._data_plane = None

    def __enter__(self):
        if not self.session_id:
            self._bootstrap_session()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()

    def _bootstrap_session(self):
        """Bootstrap the session by making a GET request."""
        base_url = f"{self.router_url}/v1/namespaces/{self.namespace}/agent-runtimes/{self.agent_name}/invocations/"

        response = requests.get(base_url, timeout=(self.connect_timeout, self.timeout))

        if response.status_code == 200:
            self.session_id = response.headers.get("x-agentcube-session-id")
            if not self.session_id:
                raise SessionError("Session ID not returned in response header")

        self._data_plane = base_url

    def invoke(self, payload: Dict[str, Any], timeout: Optional[int] = None) -> Dict[str, Any]:
        """Invoke the agent with a payload."""
        if not self._data_plane:
            raise SessionError("Data plane not initialized")

        if not self.session_id:
            self._bootstrap_session()

        headers = {
            "Content-Type": "application/json",
            "x-agentcube-session-id": self.session_id,
        }

        read_timeout = timeout or self.timeout
        response = requests.post(
            self._data_plane,
            json=payload,
            headers=headers,
            timeout=(self.connect_timeout, read_timeout),
        )

        if response.status_code != 200:
            raise SessionError(f"Invocation failed: {response.text}")

        return response.json()

    def close(self):
        """Close the session."""
        self._data_plane = None
        self.session_id = None

