def pack(
    workspace: str = typer.Option(".", help="Workspace directory"),
    name: str = typer.Option(..., help="Agent name"),
    image: str = typer.Option(..., help="Container image"),
):
    """Package an agent runtime."""
    rprint(f"[green]Packing agent:[/green] {name}")
    rprint(f"[green]Image:[/green] {image}")


