def build(
    name: str = typer.Option(..., help="Agent name"),
    tag: str = typer.Option("latest", help="Image tag"),
):
    """Build an agent runtime."""
    rprint(f"[green]Building agent:[/green] {name}:{tag}")


@app.command()
def publish(
    name: str = typer.Option(..., help="Agent name"),
    registry: str = typer.Option("ghcr.io", help="Container registry"),
):
